def cal_priority(status, num_neighboring_machine, processing_time, start_time, delivery_time, available_time, num_neighboring_operation, utilization, processing_tm):
    slack = delivery_time - available_time - processing_time

    # Dynamic slack urgency factor from Algorithm 1 (improved with normalization)
    if slack < 0:
        slack_urgency = 1.0 / (1.0 + abs(slack))
    else:
        slack_urgency = 0.0

    # Processing time deviation from average (processing_tm assumed average)
    if processing_tm > 0:
        pt_deviation = abs(processing_time - processing_tm) / processing_tm
    else:
        pt_deviation = processing_time if processing_time > 0 else 0.0

    # Exponential decay for pt_deviation to reduce impact of large deviations
    pt_deviation_exp = 1.0 - 1.0 / (1.0 + pt_deviation)

    # Machine utilization penalty from Algorithm 1 (improved)
    if num_neighboring_machine > 0:
        if utilization > 0:
            util_adjustment = utilization / num_neighboring_machine
        else:
            util_adjustment = 0.0
        util_penalty = 1.0 - min(1.0, util_adjustment)
    else:
        util_penalty = 1.0

    # ATC factor from Algorithm 2 with adaptive k based on slack
    base_k = 2.0
    if slack > 0:
        adaptive_k = base_k * (1.0 + 1.0 / (1.0 + slack))
    else:
        adaptive_k = base_k * (1.0 + abs(slack) / (1.0 + abs(slack)))

    # Use average processing time as lookahead parameter T
    T = processing_tm if processing_tm > 0 else 1.0
    if T > 0:
        atc_factor = 1.0 - 1.0 / (1.0 + max(0.0, slack) / (adaptive_k * T))
    else:
        atc_factor = 0.0

    # Normalize by remaining operations
    if num_neighboring_operation > 0:
        norm = num_neighboring_operation
    else:
        norm = 1.0

    # Composite priority combining both algorithms with balanced weights
    priority = (delivery_time * (1.0 + slack_urgency) + 
                pt_deviation_exp * 5.0 + 
                processing_time * (1.0 - util_penalty) - 
                atc_factor * 8.0) / norm

    # Ensure non-negative output
    result = max(0.0, priority)

    return priority

